import pandas as pd
import os
import numpy as np

Dataset_x = [] #存放慣性訊號
Dataset_y = [] #存放慣性訊號對應的運動動作類別
CLASSES = ['Pitching', 'Batting', 'Forehand', 'Backhand', 'Dribbling', 'Shooting',
           'Underhand Serve', 'Overhead Serve', 'Forehand Serve', 'Backhand Serve']
IMAGE_SIZE = [6, 1000] #慣性訊號組合成的訊號影像尺寸 (channels, time_steps)  #要改

folder = '/content/drive/MyDrive/processed_results'
#資料存放在Google Drive的路徑

# Create a dictionary to map action codes (e.g., 'AC01') to integer class labels
action_code_to_label = {}
for i, class_name in enumerate(CLASSES):
    # Assuming action codes are 'AC01', 'AC02', ..., 'AC10'
    # and map directly to the index of CLASSES
    action_code = f"AC{i+1:02d}"
    action_code_to_label[action_code] = i

print("Action Code to Label Map:")
print(action_code_to_label)

# Iterate through the files in the specified folder
for filename in os.listdir(folder): # Extract action code from filename
    if filename.endswith('.xlsx'):
        filepath = os.path.join(folder, filename)
        parts = filename.split('_') # Filename format: P01_AC01_01_GROUP01.xlsx
        if len(parts) >= 2:
            action_code = parts[1]
            if action_code in action_code_to_label:
                class_label = action_code_to_label[action_code]
            else:
                print(f"Warning: Unknown action code '{action_code}' in file '{filename}'. Skipping.")
                continue
        else:
            print(f"Warning: Filename '{filename}' does not match expected format. Skipping.")
            continue
        # Read data from Excel file, assuming the first row is a header and should be skipped
        try:
            df = pd.read_excel(filepath, header=None, skiprows=1) # Skip the first row as it appears to be a header
            data = df.values # Convert DataFrame to NumPy array
            data = data.T # Transpose the data to (channels, time_steps) i.e., 6x500

            # Ensure data shape matches expected (channels, time_steps)
            if data.shape == (IMAGE_SIZE[0], IMAGE_SIZE[1]):
                Dataset_x.append(data)
                Dataset_y.append(class_label)
            else:
                print(f"Warning: Data shape for '{filename}' is {data.shape}, expected ({IMAGE_SIZE[0]}, {IMAGE_SIZE[1]}) after skipping header and transposing. Skipping.")
        except Exception as e:
            print(f"Error reading file {filename}: {e}. Skipping.")

# Convert lists to NumPy arrays
Dataset_x = np.array(Dataset_x)
Dataset_y = np.array(Dataset_y)

# Reshape Dataset_x to add the channel dimension
# Original shape: (num_samples, channels, time_steps)
# Desired shape: (num_samples, channels, time_steps, 1)
Dataset_x = Dataset_x.reshape(Dataset_x.shape[0], IMAGE_SIZE[0], IMAGE_SIZE[1], 1)

print(f"Loaded {len(Dataset_x)} samples.")
print(f"Dataset_x shape: {Dataset_x.shape}")
print(f"Dataset_y shape: {Dataset_y.shape}")

#畫出資料集類別分佈的長條圖，檢查資料集是否平衡。
