"""三、建立AI模型進行運動動作分類

![image.png](data:image/png;base64,)
"""

# 建立一個卷積神經網路 (CNN) 分類模型，用來做運動動作類別的分類
## 可自行調整的參數為filters、kernel_size、Layer(直接加上去)、pool_size、Dense、Dropout...

from keras.models import Sequential
from keras.layers import Dense, Conv2D, Activation, MaxPool2D, Flatten, Dropout, BatchNormalization, GlobalAveragePooling2D

model = Sequential()

# Layer 1 #kernal size 可改
model.add(Conv2D(filters = 32, kernel_size = (3,3), padding = 'Same', input_shape=(IMAGE_SIZE[0], IMAGE_SIZE[1], 1))) # Adjusted input_shape
model.add(BatchNormalization()) # Batch Normalization
model.add(Activation("relu")) # ReLU活化函數

# Layer 2
model.add(Conv2D(filters = 32, kernel_size = (3,3), padding = 'Same'))
model.add(BatchNormalization()) # Batch Normalization
model.add(Activation("relu")) # ReLU活化函數

# MaxPooling Layer
model.add(MaxPool2D(pool_size=(2, 2)))

#Layer 3
model.add(Conv2D(filters = 64, kernel_size = (3,3), padding = 'Same'))
model.add(BatchNormalization()) # Batch Normalization
model.add(Activation("relu")) # ReLU活化函數

# Layer 4
model.add(Conv2D(filters = 64, kernel_size = (3,3), padding = 'Same'))
model.add(BatchNormalization()) # Batch Normalization
model.add(Activation("relu")) # ReLU活化函數

# Layer 5
model.add(Conv2D(filters = 128, kernel_size = (3,3), padding = 'Same'))
model.add(BatchNormalization()) # Batch Normalization
model.add(Activation("relu")) # ReLU活化函數

# MaxPooling Layer
model.add(MaxPool2D(pool_size=(2, 2)))

# 全連接層
model.add(Flatten()) # 使用Flatten()將feature map展平為一維向量
model.add(Dense(128)) # 添加全連接層（Dense）
model.add(BatchNormalization()) # Batch Normalization
model.add(Activation("relu")) # ReLU活化函數
model.add(Dropout(0.5)) # 使用Dropout層以隨機丟棄50%的神經元來減少過擬合

# Output Layer
model.add(Dense(len(CLASSES), activation='softmax')) # 輸出層，具有10個神經元（對應10個類別）

model.summary()

# 1) 分別建立 train / val / test 的 generator（val / test 不做隨機增強）
from tensorflow.keras.preprocessing.image import ImageDataGenerator

train_gen = ImageDataGenerator(
    rescale=1/1,
)

val_gen = ImageDataGenerator(rescale=1/1)
test_gen = ImageDataGenerator(rescale=1/1)


# 2) 由陣列產生資料流（驗證/測試集不要做增強、不要 shuffle）
train_flow = train_gen.flow(X_train, y_train, batch_size=8, shuffle=True, seed=15)
val_flow   = val_gen.flow(X_val,   y_val,   batch_size=8, shuffle=False)
test_flow  = test_gen.flow(X_test,  y_test,  batch_size=8, shuffle=False)

# 3) 模型編譯與訓練（用 .flow() 的輸出）
## 可自行調整的參數為learning_rate(通常要小於0.01)、Adam函式、epochs

from tensorflow.keras.optimizers import Adam
from keras.callbacks import ModelCheckpoint
from keras.models import load_model

optimizer = Adam(learning_rate=0.0001) # Define the optimizer，Learning Rate設為0.001 可改

# Model Compilation
model.compile(optimizer = optimizer, loss = "categorical_crossentropy", metrics=["accuracy"])
# 使用準確率（Accuracy）作為模型的評估指標

ckpt = ModelCheckpoint(
    filepath='best_valacc.h5',    # 儲存路徑
    monitor='val_accuracy',       # 監控指標
    mode='max',                         # 越大越好
    save_best_only=True,          # 只存最好的
    verbose=1
)

history = model.fit(
    train_flow,
    validation_data=val_flow,
    callbacks = ckpt,
    epochs=50, #可改
    verbose=1)

best_model = load_model('best_valacc.h5')  #讀取訓練過程中表現最好的那一個模型

# 畫出訓練過程中的損失函數及準確率隨著epoch的變化

acc = history.history['accuracy']
val_acc = history.history['val_accuracy']

loss = history.history['loss']
val_loss = history.history['val_loss']

epochs= range(len(acc))

plt.figure(figsize=(16, 5))
plt.subplot(121)
plt.plot(epochs, acc, label='Train_acc')
plt.plot(epochs, val_acc, label='Val_acc')
plt.legend()
plt.title('Accuracy')

plt.subplot(122)
plt.plot(epochs, loss, label='Train_loss')
plt.plot(epochs, val_loss, label='Val_loss')
plt.legend()
plt.title('Loss')
plt.show()

#將表現最好的模型拿來做測試

score = best_model.evaluate(test_flow, verbose=0)
print("Test Loss:",score[0]) # score[0]為loss
print("Test Accuracy:",score[1]) # score[1]為accuracy

#將表現最好的模型再用訓練資料跑一次，確認準確率不變。

score = best_model.evaluate(train_flow, verbose=0)
print("Train Loss:",score[0]) # score[0]為loss
print("Train Accuracy:",score[1]) # score[1]為accuracy

