# 輸出每個類別在混淆矩陣中的錯誤預測數量和正確預測的百分比

for i in range(len(confusion_mtx)):
    true_positives = confusion_mtx[i][i]
    total_for_class = sum(confusion_mtx[i]) # This is the actual number of samples for class i in the test set
    wrong_predictions = total_for_class - true_positives

    print("Class:",str(i))
    print("Number of Wrong Prediction:", str(wrong_predictions), "out of", str(total_for_class))
    if total_for_class > 0:
        print("Percentage of True Prediction: {:.2f}%".format(true_positives / total_for_class * 100))
    else:
        print("Percentage of True Prediction: 0.00%") # Handle cases where a class might have no samples
    print("***********************************************************")

"""## 可視化模型預測的結果"""

# 定義一個繪圖函數
def plot_image(i, predictions_array, true_label , img):
  true_label, img = true_label[i], img[i,:,:,0] # 正確的標籤與圖像
  img_to_plot = img # img already has shape (6, 1000), no need to squeeze

  # 定義軸的格線和刻度
  plt.grid(False)
  plt.xticks([]) #傳遞一個空列表會刪除所有X軸刻度
  plt.yticks([])

  # Plot the image with specific colormap and aspect
  plt.imshow(img_to_plot, cmap='viridis', aspect='auto')
  plt.xlabel('Time Steps') # Add x-axis label
  plt.ylabel('Channels') # Add y-axis label
  plt.colorbar(label='Amplitude') # Add colorbar

  # 預測出來的label
  predicted_label = np.argmax(predictions_array) # array中的最大值

  if predicted_label == true_label:
    color = "blue"
  else:
    color = "red"
  # 定義X軸的主題(預測的類別 預測的機率 真正的類別) :2.0f是取到浮點數小數點後2位
  plt.xlabel("{} {:2.0f}% ({})".format(CLASSES[predicted_label],
                                100*np.max(predictions_array),
                                CLASSES[true_label]),
                                color=color)

# 定義一個可以將值可視化的函數
def plot_value_array(i, predictions_array, true_label):
  true_label = true_label[i] # 正確的標籤
  plt.grid(True)
  plt.xticks(range(len(CLASSES))) # 設定X軸刻度為類別數量
  plt.yticks([0,0.5,1]) # 設定Y軸刻度
  # 繪製長條圖
  thisplot = plt.bar(range(len(CLASSES)), predictions_array, color="#777777")
  # y軸的刻度限制
  plt.ylim([0, 1])
  # 預測出來的label array中的最大值
  predicted_label = np.argmax(predictions_array)

  thisplot[predicted_label].set_color('red')
  thisplot[true_label].set_color('blue')

